	// Safe read flags (-I device identity, -t throughput test) remain unblocked.
	regexp.MustCompile(`(?i)\bhdparm\b.*--security-`),
	regexp.MustCompile(`(?i)\bhdparm\b.*\s-[yYW]\b`),
